import heapq

# Common backbone idea: Both algorithms prioritize customer selection by calculating a cost or score based on distance, time window penalties, and truck distribution.

# New algorithm: {Use a priority queue to dynamically select the customer with the lowest adjusted priority, considering travel time, wait time, and load balancing among trucks.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_priority(customer_index):
        customer_pos = unvisited_customers[customer_index]
        time_window = time_windows[customer_index]

        # Calculate travel time to customer
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        # Time window adjustment: Wait time and missed penalties
        if arrival_time < time_window[0]:
            wait_time = time_window[0] - arrival_time
        else:
            wait_time = 0
        if arrival_time > time_window[1]:
            missed_penalty = (arrival_time - time_window[1]) * 5
        else:
            missed_penalty = wait_time * 2

        # Load balance adjustment: Encourage equal distribution of trucks
        trucks_closer = sum(euclidean_distance(truck_pos, customer_pos) < travel_time for truck_pos in all_truck_pos)
        balance_penalty = trucks_closer / len(all_truck_pos)

        # Composite priority score
        priority = travel_time + missed_penalty + balance_penalty
        return priority

    # Use a priority queue to select the next customer
    min_heap = []
    for i in range(len(unvisited_customers)):
        priority = calculate_priority(i)
        heapq.heappush(min_heap, (priority, i))

    # Get customer with lowest priority score
    if min_heap:
        _, best_node = heapq.heappop(min_heap)
    else:
        best_node = None

    return best_node
